def extract_descriptor(title, desc, body, company):
    """Pull a short phrase (under 60 chars) describing what the company does."""
    noise = re.compile(
        r'^(home|welcome|about|index|homepage|official site|website)[\s\-|:]*',
        re.I
    )
    co_words = set(re.split(r'\W+', company.lower()))

    for text in [desc, title, body]:
        text = text.strip()
        if not text:
            continue
        if noise.match(text):
            continue
        # strip leading company name from descriptor
        for w in co_words:
            if w and text.lower().startswith(w):
                text = re.sub(re.escape(w), '', text, count=1, flags=re.I).strip(' ,-')
